// ─── CONFIRMACIÓN DE ELIMINACIÓN ─────────────────────────────────────────────
const confirmarEliminar = (mensaje, callback) => {
  if (window.confirm(mensaje || "¿Estás seguro que deseas eliminar este registro? Esta acción no se puede deshacer.")) {
    callback();
  }
};

// ─── HELPERS DE PROTECCIÓN — validación antes de eliminar ─────────────────────

// Verifica si un lote puede eliminarse
const puedeEliminarLote = (loteId, state) => {
  const id = String(loteId);
  const razones = [];

  // En asignaciones de ciclos
  const enCiclo = (state.ciclos||[]).some(c =>
    (c.asignaciones||[]).some(a => String(a.loteId) === id)
  );
  if (enCiclo) razones.push("está asignado en un ciclo agrícola");

  // En insumos
  if ((state.insumos||[]).some(i => String(i.loteId) === id))
    razones.push("tiene registros de insumos asociados");

  // En diesel
  if ((state.diesel||[]).some(d => String(d.loteId) === id))
    razones.push("tiene registros de diesel asociados");

  // En rentas
  if ((state.rentas||[]).some(r => String(r.loteId) === id))
    razones.push("tiene rentas registradas");

  // En egresos
  if ((state.egresosManual||[]).some(e => String(e.loteId) === id))
    razones.push("tiene egresos registrados");

  return razones;
};

// Verifica si un productor puede eliminarse
const puedeEliminarProductor = (prodId, state) => {
  const id = String(prodId);
  const razones = [];

  // En ciclos (productores del ciclo + asignaciones)
  const enCiclo = (state.ciclos||[]).some(c =>
    (c.productores||[]).some(p => String(p) === id) ||
    (c.asignaciones||[]).some(a => String(a.productorId) === id)
  );
  if (enCiclo) razones.push("está registrado en ciclos agrícolas");

  // En expedientes de crédito
  if ((state.expedientes||[]).some(e => String(e.productorId) === id))
    razones.push("tiene expedientes de crédito");

  // En insumos
  if ((state.insumos||[]).some(i => String(i.productorId) === id))
    razones.push("tiene registros de insumos");

  // En dispersiones
  if ((state.dispersiones||[]).some(d => String(d.productorId) === id))
    razones.push("tiene dispersiones de crédito");

  // En egresos
  if ((state.egresosManual||[]).some(e => String(e.productorId) === id))
    razones.push("tiene egresos registrados");

  // En rentas
  if ((state.rentas||[]).some(r => String(r.productorId) === id))
    razones.push("tiene rentas registradas");

  return razones;
};

// Verifica si una máquina puede eliminarse
const puedeEliminarMaquina = (maqId, state) => {
  const razones = [];
  if ((state.horasMaq||[]).some(h => h.maquinariaId === maqId || h.maqId === maqId))
    razones.push("tiene registros de horas de trabajo");
  if ((state.bitacora||[]).some(b => b.maquinariaId === maqId))
    razones.push("aparece en registros de bitácora");
  return razones;
};

// Verifica si un operador puede eliminarse
const puedeEliminarOperador = (opId, state) => {
  const razones = [];
  if ((state.bitacora||[]).some(b => String(b.operadorId) === String(opId) || b.operador === opId))
    razones.push("aparece en registros de bitácora");
  if ((state.horasMaq||[]).some(h => String(h.operadorId) === String(opId)))
    razones.push("tiene registros de horas de trabajo");
  return razones;
};

// ─── MODAL DE CANCELACIÓN ─────────────────────────────────────────────────────
const MOTIVOS_CANCELACION = [
  "Error en captura",
  "Cancelación de solicitud",
  "Devolución",
  "Duplicado",
  "Otro",
];

function ModalCancelacion({ titulo, onConfirmar, onCerrar }) {
  const [motivo, setMotivo] = useState(MOTIVOS_CANCELACION[0]);
  const [comentario, setComentario] = useState("");

  return (
    <Modal title={`Cancelar: ${titulo}`} onClose={onCerrar}
      footer={
        <>
          <button className="btn btn-secondary" onClick={onCerrar}>← Volver</button>
          <button className="btn btn-danger" onClick={() => {
            if (!motivo) return;
            onConfirmar({ motivo, comentario });
          }}>🚫 Confirmar Cancelación</button>
        </>
      }>
      <div style={{marginBottom:12,padding:"10px 14px",background:"#fff3cd",borderRadius:8,border:"1px solid #ffc107",fontSize:13,color:"#856404"}}>
        ⚠️ Este registro quedará <strong>cancelado e inhabilitado</strong>. No se sumará en totales pero quedará visible en el historial. Solo el Administrador puede reactivarlo.
      </div>
      <div className="form-group">
        <label className="form-label">Motivo de cancelación *</label>
        <select className="form-select" value={motivo} onChange={e => setMotivo(e.target.value)}>
          {MOTIVOS_CANCELACION.map(m => <option key={m} value={m}>{m}</option>)}
        </select>
      </div>
      <div className="form-group">
        <label className="form-label">Comentario adicional (opcional)</label>
        <input className="form-input" value={comentario}
          onChange={e => setComentario(e.target.value)}
          placeholder="Describe el motivo con más detalle..." />
      </div>
    </Modal>
  );
}

// ─── MODAL DE REACTIVACIÓN ────────────────────────────────────────────────────
function ModalReactivacion({ titulo, onConfirmar, onCerrar }) {
  const [motivo, setMotivo] = useState("Cancelación incorrecta");
  const [comentario, setComentario] = useState("");

  return (
    <Modal title={`Reactivar: ${titulo}`} onClose={onCerrar}
      footer={
        <>
          <button className="btn btn-secondary" onClick={onCerrar}>← Volver</button>
          <button className="btn btn-primary" onClick={() => onConfirmar({ motivo, comentario })}>
            ✅ Confirmar Reactivación
          </button>
        </>
      }>
      <div style={{marginBottom:12,padding:"10px 14px",background:"#d4edda",borderRadius:8,border:"1px solid #28a745",fontSize:13,color:"#155724"}}>
        ✅ Este registro volverá a estar <strong>activo</strong> y se sumará en los totales.
      </div>
      <div className="form-group">
        <label className="form-label">Motivo de reactivación *</label>
        <select className="form-select" value={motivo} onChange={e => setMotivo(e.target.value)}>
          <option value="Cancelación incorrecta">Cancelación incorrecta</option>
          <option value="Error al cancelar">Error al cancelar</option>
          <option value="Otro">Otro</option>
        </select>
      </div>
      <div className="form-group">
        <label className="form-label">Comentario adicional (opcional)</label>
        <input className="form-input" value={comentario}
          onChange={e => setComentario(e.target.value)}
          placeholder="Explica por qué se reactiva..." />
      </div>
    </Modal>
  );
}

// ─── BADGE CANCELADO ──────────────────────────────────────────────────────────
function BadgeCancelado({ registro }) {
  if (!registro?.cancelado) return null;
  return (
    <span title={`Cancelado: ${registro.motivoCancelacion || ""} — ${registro.fechaCancelacion || ""}`}
      style={{fontSize:9,fontWeight:700,padding:"2px 6px",borderRadius:8,
        background:"#c0392b22",color:"#c0392b",border:"1px solid #c0392b44",
        marginLeft:4,verticalAlign:"middle",letterSpacing:0.5}}>
      CANCELADO
    </span>
  );
}

function LoginScreen({ onLogin }) {
  const [user, setUser] = useState("");
  const [pass, setPass] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = () => {
    setLoading(true);
    setTimeout(() => {
      const baseOvr = window.__agroBaseOverrides || {};
      const todosU = [
        ...USUARIOS.map(u => baseOvr[u.id] ? {...u,...baseOvr[u.id]} : u),
        ...(window.__agroExtraUsers||[])
      ];
      const u = todosU.find(u => u.usuario === user.trim().toLowerCase() && u.password === pass && u.activo!==false);
      if (u) { setError(""); onLogin(u); }
      else { setError("Usuario o contraseña incorrectos"); setLoading(false); }
    }, 400);
  };

  return (
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#1a2e1a 0%,#2d5a1b 50%,#1a3d2e 100%)",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'DM Sans',sans-serif"}}>
      <div style={{background:"white",borderRadius:20,padding:"48px 40px",width:360,boxShadow:"0 24px 64px rgba(0,0,0,0.35)"}}>
        <div style={{textAlign:"center",marginBottom:32}}>
          <div style={{fontSize:48,marginBottom:8}}>🌽</div>
          <div style={{fontFamily:"'Playfair Display',serif",fontSize:26,fontWeight:700,color:"#1a2e1a"}}>AgroSistema</div>
          <div style={{fontSize:14,color:"#5a7a5a",marginTop:4}}>Almacenes Santa Rosa · Charay</div>
        </div>

        <div style={{marginBottom:16}}>
          <label style={{fontSize:12,fontWeight:600,color:"#4a6a4a",display:"block",marginBottom:6}}>Usuario</label>
          <input
            value={user} onChange={e=>setUser(e.target.value)}
            onKeyDown={e=>e.key==="Enter"&&handleLogin()}
            placeholder="admin / socio / campo"
            style={{width:"100%",padding:"11px 14px",border:"1.5px solid #d0e0d0",borderRadius:10,fontSize:14,outline:"none",boxSizing:"border-box",transition:"border 0.15s"}}
            onFocus={e=>e.target.style.borderColor="#2d7a3a"}
            onBlur={e=>e.target.style.borderColor="#d0e0d0"}
          />
        </div>
        <div style={{marginBottom:24}}>
          <label style={{fontSize:12,fontWeight:600,color:"#4a6a4a",display:"block",marginBottom:6}}>Contraseña</label>
          <input
            type="password" value={pass} onChange={e=>setPass(e.target.value)}
            onKeyDown={e=>e.key==="Enter"&&handleLogin()}
            placeholder="••••••••"
            style={{width:"100%",padding:"11px 14px",border:"1.5px solid #d0e0d0",borderRadius:10,fontSize:14,outline:"none",boxSizing:"border-box"}}
            onFocus={e=>e.target.style.borderColor="#2d7a3a"}
            onBlur={e=>e.target.style.borderColor="#d0e0d0"}
          />
        </div>

        {error && <div style={{background:"#fdf0ef",border:"1px solid #e74c3c",borderRadius:8,padding:"10px 14px",fontSize:13,color:"#c0392b",marginBottom:16}}>{error}</div>}

        <button onClick={handleLogin} disabled={loading}
          style={{width:"100%",padding:"13px",background:loading?"#7aaa6a":"#2d7a3a",color:"white",border:"none",borderRadius:10,fontSize:15,fontWeight:700,cursor:loading?"wait":"pointer",transition:"background 0.15s"}}>
          {loading ? "Verificando..." : "Ingresar →"}
        </button>

        <div style={{marginTop:24,padding:"14px",background:"#f0f7f0",borderRadius:10,fontSize:11,color:"#5a7a5a"}}>
          <div style={{fontWeight:600,marginBottom:4}}>Perfiles disponibles:</div>
          {Object.entries(ROLES).map(([k,r])=>(
            <div key={k} style={{marginTop:2}}>{r.icon} <strong>{k}</strong> — {r.label}</div>
          ))}
        </div>
      </div>
    </div>
  );
}


